import axios from 'axios'
import { Message } from 'element-ui'
import router from '@/router'

const service = axios.create({
    timeout: 0
})

let authErrorCount = 0;   // 认证错误计数器
let networkErrorReported = false // 新增网络错误标记

/** 重置认证错误计数器 */
export function resetAuthErrorCount() {
    authErrorCount = 0;
}

/** 获取认证错误计数器的值 */
export function getAuthErrorCount() {
    return authErrorCount;
}

/** 请求拦截器 */
service.interceptors.request.use(
    config => {
        // 重置网络错误标记（每次请求前重置）
        if (networkErrorReported) networkErrorReported = false

        const token = localStorage.getItem('token')
        if (token) {
            config.headers['Authorization'] = `Bearer ${token}`
        }
        config.headers['Timestamp'] = Date.now()

        if (config.data instanceof FormData) {
            config.headers['Content-Type'] = 'multipart/form-data'
        } else if (config.method === 'post') {
            config.headers['Content-Type'] = 'application/json'
        }

        return config
    },
    error => Promise.reject(error)
)

/** 响应拦截器 */
service.interceptors.response.use(
    response => {
        const res = response.data;
        if (!res.code || res.code === 2000 || res.code === 5002 || res.code === 5003) return response;
        switch (res.code) {
            case 2015:
                handleAuthError(res.message, '会话过期')
                break
            case 2001:
                handleAuthError(res.message)
                break
            case 2023:
                handleAuthError(res.message, '2023')
                break
            default:
                Message.error(res.message || '请求错误');
                break
        }

        return Promise.reject(res)
    },
    error => {
        // 处理响应错误
        if (error.response) {
            const { status } = error.response

            if (status === 404) return Promise.reject(error)

            if (status === 401) {
                handleAuthError('登录令牌失效，请重新登录')
            } else if (status >= 500) {
                handleAuthError('登录令牌失效，请重新登录')
            } else {
                Message.error(error.response.data.message || `请求错误：${status}`)
            }
        }
        // else {
        //     // 新增网络错误处理逻辑
        //     handleNetworkError()
        // }

        return Promise.reject(error)
    }
)

/** 统一处理认证错误 */
function handleAuthError(message = '', code = '') {
    if (getAuthErrorCount() == 0) {
        increaseAuthErrorCount()
        Message.error(message)
        if (code != '2023') {
            localStorage.removeItem('token')
            router.push({
                path: '/login',
                query: {redirect: router.currentRoute.fullPath}
            })
        }
        setTimeout(() => {
            resetAuthErrorCount()
        }, 3000)

    }
}

/** 增加认证错误计数器的值 */
function increaseAuthErrorCount() {
    authErrorCount++;
}

/** 新增网络错误处理函数 */
function handleNetworkError() {
    if (!networkErrorReported) {
        networkErrorReported = true
        Message({
            message: '网络连接异常，请检查网络',
            type: 'error',
            duration: 3000,
            onClose: () => {
                // 3秒后允许重新报告
                setTimeout(() => (networkErrorReported = false), 3000)
            }
        })
    }
}

export default service
