<!--
 * @Description: 摄像头分组管理
 * @Author: zhangbo
 * @Date: 2026-01-21
-->
<template>
  <div class="CameraGroup-body">
    <LTPages
        :title="'摄像头分组管理'"
        :isNormal="false"
        :formConfig="formConfig"
        :buttonConfig="buttonConfig"
        :tableConfig="tableConfig"
        @setSearchFields="getSearchFields"
        @setSelectionTable="getSelectionTable"
        @tablePageForm="getTableForm"
    ></LTPages>
    <!--新增摄像头分组===============-->
    <LTDialog
        v-if="CameraGroupMsg.isShow"
        :DialogLTMsg="CameraGroupMsg"
        @close="CameraGroupMsg.isShow = false">
      <addCameraGroup :CameraGroupMsg="CameraGroupMsg" @cancel="cancelAdd"></addCameraGroup>
    </LTDialog>
    <!--到底啦！===============-->
  </div>
</template>
<script>
import {deleteCameraGroupApi, queryCameraGroupApi} from "@/api/System/CameraGroup";
import { treeDataTranslate } from "@/utils/table.js";
import addCameraGroup from "./components/add.vue";

export default {
  name: "CameraGroup",
  components: {addCameraGroup},
  data() {
    return {
      //搜索配置
      formConfig: {
        labelWidth: "100px",
        itemNum: 5,
        formItemList: [

          {
            id: 1,
            type: 'text',
            prop: 'groupName',
            label: '摄像头分组名称',
            value: '',
            list:[]
          }
        ]
      },
      buttonConfig: [
        {
          label: '添加',
          icon: "icon zhb-iconfont zhb-iconzengjia",
          click: () => {
            this.CameraGroupMsg.title = '新增摄像头分组'
            this.CameraGroupMsg.type = 'add'
            this.CameraGroupMsg.isShow = true;
          }
        },
        {
          label: '删除',
          icon: "icon zhb-iconfont zhb-iconshanchu2",
          click: () => {
            if (this.checkTabelData.length == 0) return this.$message.warning({
              message: "请至少选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            // if(this.checkTabelData[0].childMCameraArray && this.checkTabelData[0].childMCameraArray.length) return this.$message.warning({
            //   message: "该摄像头分组下存在设备，不允许删除！",
            //   showClose: true,
            //   duration: 1000
            // });
            this.$confirm('此操作将删除该摄像头分组, 是否继续?', '提示', {
              confirmButtonText: '确定',
              cancelButtonText: '取消',
              type: 'warning'
            }).then(() => {
              var ids = []
              this.checkTabelData.forEach(item =>{
                ids.push(item.id)
              })
              deleteCameraGroupApi({ids:ids}).then(res=>{
                if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
                this.queryCameraGroup()
                this.$message({
                  type: 'success',
                  message: '删除成功！'
                });
              })
            }).catch(() => {
              this.$message({
                type: 'info',
                message: '已取消删除'
              });
            });
          }
        }
      ],
      //表格配置
      tableConfig: {
        tableLoading:true,
        tableRefresh: true,
        tableHead: [
          {
            label: '摄像头分组名称',
            prop: 'groupName',
          },
          {
            prop: 'createByName',
            label: "创建人员"
          },
          {
            prop: 'createTime',
            label: "创建时间"
          },
          {
            prop: 'remarks',
            label: "分组描述"
          }
        ],
        tableData: [],
        columnButton: [
          {
            label: '编辑',
            icon: "zhb-iconwenbenbianjitianchong",
            click: (row) => {
              this.CameraGroupMsg.row = row;
              this.CameraGroupMsg.title = '编辑摄像头分组'
              this.CameraGroupMsg.type = 'edit'
              this.CameraGroupMsg.isShow = true;
            }
          },
        ],
        columnWidth: '130',
        // tableColWidth:'155',
        total: 10,
        pageSize: 10,
        currentPage: 1,
      },
      //表格勾选
      checkTabelData: [],
      //查询参数
      params: {
        pageSize: 20,
        currentPage: 1,
      },
      // 新增
      CameraGroupMsg: {
        isShow: false,
        title: '添加摄像头分组',
        //showCloseBtn: true,
        styles: {
          width: '35%',
          height: '50%'
        }
      }
    }
  },
  created() {
    this.queryCameraGroup()
  },
  methods: {
    // 关闭新增
    cancelAdd(type) {
      if (type == 0) {
        this.queryCameraGroup()
      }
      this.CameraGroupMsg.isShow = false
    },
    //表格勾选数据
    getSelectionTable(val) {
      console.log(val);
      this.checkTabelData = val
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize
      this.tableConfig.currentPage = page.pageNum
      this.params.pageSize = page.pageSize
      this.params.currentPage = page.pageNum
      this.queryCameraGroup()
    },
    //查询摄像头分组
    getSearchFields(data){
      if(data.type == 'reset'){
        this.params ={
          pageSize: 10,
          currentPage: 1
        }
      }else {
        this.params.groupName = data.groupName
      }

      this.params.currentPage = 1;
      this.tableConfig.currentPage = 1;
      this.queryCameraGroup()
    },
    queryCameraGroup(){
      this.tableConfig.tableLoading = true
      queryCameraGroupApi(this.params).then(res => {
        this.tableConfig.tableLoading = false
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        if(res.data.result.records && res.data.result.records.length!= 0){
          this.tableConfig.tableData = treeDataTranslate( res.data.result.records, 'id')
          this.tableConfig.total = res.data.result.total
        } else {
          this.tableConfig.tableData = []
          this.tableConfig.total = 0
        }


      }).catch(()=>{
        this.tableConfig.tableLoading = false
      })
    },
  },
}
</script>

<style scoped lang="scss">
  .CameraGroup-body{
    width: 100%;
    height: 100%;
  }
</style>