<!--
 * @Description: 添加摄像头分组
 * @Author: zhangbo
 * @Date: 2026/1/22
-->
<template>
  <LTAddForm @cancel="cancel"  @AddBtn="AddBtn" class="add-camrea_body">
    <template v-slot:AddContent>
      <div class="add-content_col" style="width: 100%;">
        <span><i>*</i>分组名称</span>
        <span>
           <el-input v-model="addForm['groupName']" placeholder="请输入分组名称"></el-input>
          </span>
      </div>
      <div class="add-content_col" style="width: 100%">
        <span>分组描述</span>
        <span>
            <el-input v-model="addForm['remarks']" placeholder="请输入分组描述"></el-input>
       </span>
      </div>
    </template>
  </LTAddForm>
</template>
<script>
import {insertCameraGroupApi, queryCameraGroupJsonApi, updateCameraGroupApi} from "@/api/System/CameraGroup";


export default {
  name: "add",
  props: {
    CameraGroupMsg: {
      type: Object,
      default: function () {
        return {}
      }
    }
  },
  data() {
    return {
      addForm: { },
    }
  },
  created() {
    if (this.CameraGroupMsg.type == 'edit') {
      this.addForm = JSON.parse(JSON.stringify(this.CameraGroupMsg.row))

    }
  },
  methods: {
    // 取消
    cancel() {
      this.$emit('cancel')
    },
    AddBtn(data) {
      if (!this.addForm.groupName) return this.$message.error({message: "分组名称为必填项！", showClose: true, duration: 1000});
      this.addForm['parentId'] = 0
      if (this.CameraGroupMsg.type == 'edit') {
        updateCameraGroupApi(this.addForm).then(res => {
          if (res.data.code != '2000') return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000
          });
          this.$message.success({message: "编辑摄像头分组成功!", showClose: true, duration: 1000});
          this.addForm = {}
          this.$emit('cancel', 0)
        })
      } else {
        insertCameraGroupApi(this.addForm).then(res => {
          if (res.data.code != '2000') return this.$message.error({
            message: res.data.message,
            showClose: true,
            duration: 1000
          });
          this.$message.success({message: "新建摄像头分组成功!", showClose: true, duration: 1000});
          this.addForm = {}
          this.$emit('cancel', 0)
        })
      }
    }
  }
}
</script>

<style scoped lang="scss">
  .add-camrea_body{
    height: 40vh;
    ::v-deep .add-content{
      .add-content_row{
        flex-direction: column!important;
      }
    }

    .add-content_col{
      margin-top: 15px;
    }
  }
</style>